// ==================== CONFIG ====================
#define NUM_CANAIS            10
#define FREQ_SINAL_HZ         60
#define PONTOS_POR_PERIODO    15

#define TAXA_AMOSTRAGEM       (NUM_CANAIS * FREQ_SINAL_HZ * PONTOS_POR_PERIODO)  // 18000 Hz agregada
#define AMOSTRAS_POR_CANAL    360

#define ADC_MAX               4095.0f
#define VREF                  1.8333f
#define CONST_AJUSTE_V        550.86f
#define CONST_AJUSTE_A        9.778f

#define UPDATE_DISPLAY_MS     1000

// ==================== FILTRO DAS TENSÕES ====================
// Filtro exponencial aplicado apenas no valor RMS final de V1, V2 e V3.
// Não aumenta a amostragem e quase não pesa no processamento.
// Menor V_ALPHA = mais estável/lento | maior V_ALPHA = mais rápido
#define V_ALPHA              0.70f
#define V_DEADBAND           0.10f   // ignora variações menores que 0,30 V

// quantas amostras máximas processar por passada do loop
// evita ficar preso tempo demais se acumular pendências
#define MAX_AMOSTRAS_POR_LOOP 200

// ==================== UART2 ====================
#define UART2_TX  17
#define UART2_RX  16  // não usado, mas necessário
#define UART2_BAUD 115200

// ==================== BOTÕES DE FLAG ====================
// Botões em lógica ativa HIGH:
// - solto = LOW
// - apertado = HIGH
// Ligação recomendada: botão entre GPIO e 3V3.
// O INPUT_PULLDOWN interno mantém LOW quando nenhum botão é apertado.
#define BOTAO_D19           19
#define BOTAO_D15           15
#define BOTAO_DEBOUNCE_MS   30

volatile bool eventoBotao = true;
uint8_t flagBotao = 0;
uint32_t ultimoDebounceBotaoMs = 0;

// ==================== VARIÁVEIS DEBUG ====================
bool liberarPrint = false;
char comandoSerial[20];
uint8_t idxCmd = 0;

// ==================== TIMER ====================
hw_timer_t *timer = NULL;
portMUX_TYPE timerMux = portMUX_INITIALIZER_UNLOCKED;

// em vez de bool, usa contador
volatile uint32_t amostrasPendentes = 0;
volatile uint32_t interrupcoesTimer = 0;
volatile uint32_t overflowPendencias = 0;

// ==================== BUFFERS ====================
uint16_t rawBuffer[NUM_CANAIS][AMOSTRAS_POR_CANAL];
float tensaoBuffer[NUM_CANAIS][AMOSTRAS_POR_CANAL];
volatile uint16_t indiceBuffer[NUM_CANAIS] = {0};

// ==================== MÉTRICAS ====================
